import json, sys, math
from datetime import datetime, timezone

raw = json.load(sys.stdin)
if isinstance(raw, str): raw = json.loads(raw)
if isinstance(raw, dict) and "merged" in raw: raw = raw["merged"]

def walk(node):
    if isinstance(node, dict):
        yield node
        for v in node.values(): yield from walk(v)
    elif isinstance(node, list):
        for v in node: yield from walk(v)

# locate registry + OSV payload anywhere in the merged input
registry, osv = None, None
for u in walk(raw):
    if registry is None and "package_registry" in u: registry = u.get("package_registry")
    if osv is None and "vulns" in u:                  osv = u
registry = (registry or "").strip().lower()
vulns = (osv or {}).get("vulns", []) or []

# Not a tracked registry -> no security signal at all. Exclude (lowers confidence).
if registry in ("", "none"):
    print(json.dumps({
        "data_available": False,
        "total_cve_count": 0,
        "security_posture": "Not a tracked package registry; no CVE feed available.",
        "summary": "Security excluded from the score because no OSV ecosystem applies.",
    }))
    sys.exit(0)

now = datetime.now(timezone.utc)

def parse(ts):
    if not ts: return None
    try: return datetime.fromisoformat(ts.replace("Z", "+00:00"))
    except Exception: return None

def cvss_base(vector):
    """Compute a CVSS v3.0/3.1 base score from a vector string. Returns float or None."""
    try:
        p = dict(x.split(":") for x in vector.split("/") if ":" in x)
    except Exception:
        return None
    AV={"N":0.85,"A":0.62,"L":0.55,"P":0.2}.get(p.get("AV"))
    AC={"L":0.77,"H":0.44}.get(p.get("AC"))
    UI={"N":0.85,"R":0.62}.get(p.get("UI"))
    S=p.get("S","U")
    PRm={"U":{"N":0.85,"L":0.62,"H":0.27},"C":{"N":0.85,"L":0.68,"H":0.5}}
    PR=PRm.get("C" if S=="C" else "U",{}).get(p.get("PR"))
    imp={"H":0.56,"L":0.22,"N":0.0}
    C,I,A=imp.get(p.get("C")),imp.get(p.get("I")),imp.get(p.get("A"))
    if None in (AV,AC,UI,PR,C,I,A): return None
    iss=1-(1-C)*(1-I)*(1-A)
    impact=7.52*(iss-0.029)-3.25*((iss-0.02)**15) if S=="C" else 6.42*iss
    if impact<=0: return 0.0
    expl=8.22*AV*AC*PR*UI
    score=min(1.08*(impact+expl),10) if S=="C" else min(impact+expl,10)
    return math.ceil(score*10)/10

def sev_label(v):
    # 1) GHSA/advisory string label
    ds = (v.get("database_specific") or {}).get("severity")
    if isinstance(ds, str):
        s = ds.upper()
        if s == "CRITICAL": return "critical"
        if s == "HIGH": return "high"
        if s in ("MODERATE", "MEDIUM"): return "medium"
        if s == "LOW": return "low"
    # 2) numeric or CVSS-vector score
    best = None
    for sv in v.get("severity", []) or []:
        sc = sv.get("score")
        f = None
        try: f = float(sc)
        except (TypeError, ValueError):
            if isinstance(sc, str) and sc.upper().startswith("CVSS"):
                f = cvss_base(sc)
        if f is not None: best = max(best or 0, f)
    if best is not None:
        if best >= 9.0: return "critical"
        if best >= 7.0: return "high"
        if best >= 4.0: return "medium"
        if best > 0:    return "low"
    return "unknown"

def is_fixed(v):
    for a in v.get("affected", []) or []:
        for r in a.get("ranges", []) or []:
            for e in r.get("events", []) or []:
                if "fixed" in e: return True
    return False

pkg = "unknown"
for v in vulns:
    for a in v.get("affected", []) or []:
        name = (a.get("package") or {}).get("name")
        if name: pkg = name; break
    if pkg != "unknown": break

def empty(): return {"critical":0,"high":0,"medium":0,"low":0,"unknown":0}
total_breakdown, live_breakdown, unpatched = empty(), empty(), []
for v in vulns:
    lbl = sev_label(v)
    total_breakdown[lbl] += 1
    if not is_fixed(v):
        live_breakdown[lbl] += 1
        unpatched.append(v)

unpatched_count = len(unpatched)
patched_count = len(vulns) - unpatched_count
unp_dates = [d for d in (parse(v.get("published")) for v in unpatched) if d]
days_since_oldest_unpatched = (now - min(unp_dates)).days if unp_dates else 0

PATTERNS = {
    "arbitrary code execution": ["arbitrary code","code execution","remote code","rce"],
    "SQL injection": ["sql injection"],
    "server-side request forgery (SSRF)": ["server-side request forgery","ssrf"],
    "path traversal": ["path traversal","directory traversal"],
    "OS command injection": ["command injection"],
    "denial of service": ["denial of service"],
    "cross-site scripting (XSS)": ["cross-site scripting","xss"],
    "deserialization": ["deserialization","pickle"],
}
text = " ".join(((v.get("summary","") or "")+" "+(v.get("details","") or "")).lower() for v in vulns)
patterns = [n for n,kws in PATTERNS.items() if any(k in text for k in kws)]

posture = (f"All {len(vulns)} known CVEs have fixes available; live risk is low on a current release."
           if unpatched_count == 0 else
           f"{unpatched_count} of {len(vulns)} CVEs remain unpatched; oldest is {days_since_oldest_unpatched} days old.")

print(json.dumps({
    "data_available": True,
    "package": pkg,
    "total_cve_count": len(vulns),
    "patched_count": patched_count,
    "unpatched_count": unpatched_count,
    "severity_breakdown": {k: live_breakdown[k] for k in ("critical","high","medium","low")},
    "total_severity_breakdown": total_breakdown,
    "days_since_oldest_unpatched": days_since_oldest_unpatched,
    "vulnerability_patterns": patterns,
    "security_posture": posture,
    "summary": f"{pkg} has {len(vulns)} known CVEs ({patched_count} patched, {unpatched_count} unpatched). Score reflects only the unpatched (live) surface.",
}))
